    broker_co_op boolean,
    financing_available boolean,
    beds integer,
    baths integer,
    year_built integer,
    year_renovated integer,
    square_footage integer,
    lot_size integer,
    home_warranty boolean,
    lot_dimensions character varying(100),
    garage_spaces integer,
    basement boolean,
    property_taxes integer,
    special_assessment_tax integer,
    hoa_fee numeric(15,2),
    hoa_fee_type integer,
    subdivision character varying(255),
    school_district character varying(255),
    upper_floor_area double precision,
    main_floor_area double precision,
    basement_area double precision,
    upper_floor_bedroom integer,
    main_floor_bedroom integer,
    basement_bedroom integer,
    upper_floor_bathroom integer,
    main_floor_bathroom integer,
    basement_bathroom integer,
    fireplace integer,
    lease_expiration timestamp with time zone,
    total_buildings integer,
    total_units integer,
    net_operating_income numeric(15,2),
    occupancy numeric(6,2),
    total_floors integer,
    cap_rate numeric(6,2),
    average_monthly_rate numeric(16,2),
    total_rooms integer,
    total_bedrooms integer,
    total_bathrooms integer,
    total_public_restrooms integer,
    ceiling_height integer,
    total_acres double precision,
    dryland_acres double precision,
    irrigated_acres double precision,
    grass_acres double precision,
    pasture_fenced_acres double precision,
    crp_acres double precision,
    timber_acres double precision,
    lot_acres double precision,
    balance_other_acres double precision,
    fsa_information text,
    crop_yield_history text,
    ponds integer,
    wells integer,
    soil_productivity_rating text,
    county character varying(100),
    livestock_carrying_capacity integer,
    annual_payment numeric(15,2),
    contract_expire timestamp with time zone,
    property_lat character varying(100),
    property_lon character varying(100),
    address_one text,
    address_two text,
    city character varying(255),
    postal_code character varying(10),
    is_map_view boolean NOT NULL,
    is_street_view boolean NOT NULL,
    is_arial_view boolean NOT NULL,
    create_step integer NOT NULL,
    sold_price numeric(15,2) NOT NULL,
    date_sold timestamp with time zone,
    sale_terms text,
    is_featured boolean,
    is_approved boolean,
    map_url text,
    ordering integer,
    read_by_auction_dashboard boolean NOT NULL,
    auction_location text,
    due_diligence_period integer,
    escrow_period integer,
    earnest_deposit numeric(15,2),
    earnest_deposit_type integer NOT NULL,
    highest_best_format integer NOT NULL,
    latitude character varying(251),
    longitude character varying(251),
    idx_property_id character varying(251),
    buyers_premium boolean NOT NULL,
    buyers_premium_percentage numeric(15,2),
    buyers_premium_min_amount numeric(15,2),
    added_by integer,
    agent_id integer NOT NULL,
    buyer_id integer,
    closing_status_id integer,
    country_id integer,
    domain_id integer NOT NULL,
    lot_size_unit_id integer,
    property_asset_id integer NOT NULL,
    property_type_id integer NOT NULL,
    sale_by_type_id integer,
    state_id integer,
    status_id integer,
    updated_by integer,
    winner_id integer,
    deposit_amount numeric(15,2) NOT NULL,
    is_deposit_required boolean
);


